// Map a team action to its effect: new status, which team it hands to next,
// the audit verb, and the claimant-facing message Ava will email.
const b=$json.body||{};
const action=(b.action||'').toString().toLowerCase();
const esc=s=>String(s==null?'':s).replace(/'/g,"''");
const map={
  approve:      {status:'approved', team:'Finance',             ev:'approved',       next:'Your claim has been approved by our claims team and passed to Payments for release.'},
  pay:          {status:'paid',     team:'Finance',             ev:'paid',           next:'Your payment has been released and will reach your account within 1 working day.'},
  decline:      {status:'declined', team:'Legal',  ev:'declined',       next:'After review, your claim has been declined. You can appeal within 14 days and our Complaints & Appeals team will review it.'},
  'request-info':{status:'info-requested', team:null,             ev:'info-requested', next:'We need a little more information to continue with your claim. Please reply to this email with the details requested.'},
  escalate:     {status:'referred', team:'Claims Adjuster',       ev:'escalated',      next:'Your claim has been escalated to a senior claims adjuster for review.'},
  'clear-fraud':{status:'referred', team:'Claims Adjuster',       ev:'fraud-cleared',  next:'Our checks are complete and your claim is back in normal processing with our claims team.'},
  'appeal-uphold':{status:'approved', team:'Finance',            ev:'appeal-upheld',  next:'Good news — your appeal was upheld and your claim approved. Payments will release it shortly.'}
};
const m=map[action]||{status:'updated', team:null, ev:(action||'updated'), next:'Your claim has been updated by our team.'};
const sets=["status='"+m.status+"'", "next_step='"+esc(m.next)+"'", "updated_at=now()"];
if(m.team) sets.push("team='"+esc(m.team)+"'");
return [{json:{ claim_ref:esc(b.claim_ref), actor:esc(b.actor||'Team'), team_now:esc(b.team||''), ev:m.ev, note:esc(b.note||''), set_clause:sets.join(', '), new_status:m.status }}];
